module RefModule(
    input clk,
    input rst,
    input shift_dir,
    input shift_in,
    output reg [7:0] shift_out
);

reg [7:0] unused_shift_reg;

always @(posedge clk) begin
    if (rst)
        unused_shift_reg <= 8'b00000000;
    else if (shift_dir)
        unused_shift_reg <= {unused_shift_reg[6:0], shift_in};
    else
        unused_shift_reg <= {shift_in, unused_shift_reg[7:1]};
end

assign shift_out = unused_shift_reg;

endmodule
